%[text] # Direct Time-of-Flight 3D Imaging — End-to-End Example
%[text] Simulate a 32x32 SPAD array imaging a sphere on a flat background, then recover a depth map by peak-picking each pixel's TCSPC histogram.
%%
%[text] ## Create The Scene: Ground Truth Depth Map
%[text] Create a 32x32 depth map with a sphere protruding from a flat background at 5 m. The sphere center is at 3.5 m depth.
nRows = 32;
nCols = 32;

backgroundDepth = 5.0;   % m
sphereDepth = 3.5;       % m
sphereRadius = 12;       % pixels

[cx, cy] = deal((nCols+1)/2, (nRows+1)/2);
[X, Y] = meshgrid(1:nCols, 1:nRows);
dist = sqrt((X - cx).^2 + (Y - cy).^2);

gtDepth = backgroundDepth * ones(nRows, nCols);
mask = dist <= sphereRadius;
zOffset = sqrt(max(sphereRadius^2 - dist.^2, 0)) / sphereRadius;
gtDepth(mask) = sphereDepth + (1 - zOffset(mask)) * (backgroundDepth - sphereDepth) * 0.3;

imagesc(gtDepth)
axis image
colorbar
clim([sphereDepth backgroundDepth])
title("Ground Truth Depth (m)")
xlabel("Column")
ylabel("Row")
%%
%[text] ## Convert Depth to Photon Arrival Rate Vectors
%[text] Each pixel's time-of-flight determines where the laser return pulse appears in the rate vector. A uniform ambient background is added to all bins.
params = defaultSPADParams(); % Get SPAD simulation parameters

nBins = round(params.cycleTime / params.binWidth);
binCenters = ((0:nBins-1) + 0.5) * params.binWidth;

c = 3e8;                    % speed of light (m/s)
pulseSigma = 1e-9;       % laser pulse width (s)
signalRate = 1e8;           % peak signal photon rate (photons/s)
ambientRate = 1e7;          % ambient background rate (photons/s)

rateVector = ambientRate * ones(nRows, nCols, nBins);

for r = 1:nRows
    for col = 1:nCols
        tof = 2 * gtDepth(r, col) / c;
        pulse = exp(-0.5 * ((binCenters - tof) / pulseSigma).^2);
        rateVector(r, col, :) = rateVector(r, col, :) + ...
            reshape(signalRate * pulse, 1, 1, []);
    end
end

maxRange = 7;  % m — max unambiguous range
gateOffTime = 2 * maxRange / c;
gateOffBin = round(gateOffTime / params.binWidth);
gateVector = zeros(1, nBins);
gateVector(1:gateOffBin) = 1;
%%
%[text] ## Run Simulation
%[text] Execute the SPAD simulation pipeline: photon arrival generation, SPAD avalanche physics (dead time + after-pulsing), and TDC digitization.
result = runSPADSimulation(rateVector, gateVector, params);
%%
%[text] ## Build TCSPC Histograms
%[text] For each pixel, build a TCSPC histogram from the TDC timestamps.
[counts, ~, histCenters] = buildHistogram(result, params);
%[text] ## Sample Pixel Histograms
%[text] Examine individual TCSPC histograms at selected pixels. The red dashed line marks the true time-of-flight.
samplePixels = round([cy cx; cy-10 cx; cy cx+10; 1 1]);
sampleLabels = ["Center", "Top of sphere", "Right edge", "Corner (background)"];

tiledlayout(2, 2)
for i = 1:size(samplePixels, 1)
    nexttile
    r = samplePixels(i, 1); col = samplePixels(i, 2);
    h = squeeze(counts(r, col, :))';
    bar(histCenters * 1e9, h, 1, FaceColor=[0.2 0.4 0.8])
    xlabel("Time (ns)")
    ylabel("Counts")
    trueTof = 2 * gtDepth(r, col) / c;
    xline(trueTof * 1e9, "r--", LineWidth=1.5)
    title(sprintf("%s [%d,%d] d=%.2fm", sampleLabels(i), r, col, gtDepth(r, col)))
    xlim([0 gateOffTime*1e9])
end
%%
%[text] ## Estimate Depth
%[text] For each pixel, estimate depth from the peak histogram bin using $d = t\_\\text{peak} \\cdot c / 2$.
estimatedDepth = zeros(nRows, nCols);
for r = 1:nRows
    for col = 1:nCols
        h = squeeze(counts(r, col, :))';
        [~, peakBin] = max(h);
        tof = histCenters(peakBin);
        estimatedDepth(r, col) = tof * c / 2;
    end
end

%[text] ## Depth Map Comparison
%[text] Compare the ground truth depth, estimated depth, and per-pixel error.
tiledlayout(1, 3) %[output:590c8ebe]

nexttile %[output:590c8ebe]
imagesc(gtDepth) %[output:590c8ebe]
axis image %[output:590c8ebe]
colorbar; %[output:590c8ebe]
clim([sphereDepth backgroundDepth]) %[output:590c8ebe]
title("Ground Truth Depth (m)") %[output:590c8ebe]
xlabel("Column") %[output:590c8ebe]
ylabel("Row") %[output:590c8ebe]

nexttile %[output:590c8ebe]
imagesc(estimatedDepth) %[output:590c8ebe]
axis image %[output:590c8ebe]
colorbar; %[output:590c8ebe]
clim([sphereDepth backgroundDepth]) %[output:590c8ebe]
title("Estimated Depth (m)") %[output:590c8ebe]
xlabel("Column") %[output:590c8ebe]
ylabel("Row") %[output:590c8ebe]

nexttile %[output:590c8ebe]
depthError = estimatedDepth - gtDepth;
imagesc(depthError) %[output:590c8ebe]
axis image %[output:590c8ebe]
colorbar; %[output:590c8ebe]
colormap(gca, "turbo"); %[output:590c8ebe]
title("Depth Error (m)") %[output:590c8ebe]
xlabel("Column") %[output:590c8ebe]
ylabel("Row") %[output:590c8ebe]

